static func spiral_in(node: Node2D, center: Vector2, duration: float = 0.8) -> Tween:
	if not node: return null
	var start_dist := node.global_position.distance_to(center)
	var start_angle := (node.global_position - center).angle()
	var t := node.create_tween()
	t.tween_method(func(v): node.global_position = center + Vector2(cos(start_angle+v*TAU*2), sin(start_angle+v*TAU*2))*lerpf(start_dist, 0.0, v), 0.0, 1.0, duration)
	return t

static func stagger_children(container: Node, stagger_delay: float = 0.08, duration: float = 0.3) -> Tween:
	if not container: return null
	var t := container.create_tween()
	var i := 0
	for child in container.get_children():
		if child is CanvasItem:
			child.modulate.a = 0; child.scale = Vector2.ZERO
			var tt := container.create_tween()
			tt.set_parallel(true)
			tt.tween_property(child, "modulate:a", 1.0, duration).set_delay(i*stagger_delay)
			tt.tween_property(child, "scale", Vector2.ONE, duration).set_delay(i*stagger_delay).set_trans(Tween.TRANS_BACK)
			i += 1
	return t
